function fabDraw() {
  fab.autoHome();
  fab.setTemps(205, 60);
  const z = 0.2;

  // Test a series of retraction amounts
  const numLines = 5;
  const spacing = 10;
  const lineLength = 100;
  let retraction = 5;
  for (let i = 0; i < numLines; i++) {
    fab.push();
    fab.translate(50, 50 + spacing * i, z);
    fab.retractAmount(retraction);
    fab.travelTo(0, 0, 0);
    fab.extrudeX(lineLength);
    fab.pop();
    retraction += 1;
  }
}

